SELECT COUNT(comment_id) AS comment_count
FROM case_comments
WHERE case_id = 1;

SELECT SUM(cases) AS total_cases
FROM covid_cases
WHERE university_id = 1;

SELECT total_cases, last_updated
FROM case_summary
WHERE university_id = 1;

SELECT SUM(cases) AS total_cases
FROM covid_cases
WHERE report_date = '2020-10-12';

SELECT university_name 
FROM universities 
ORDER BY university_name ASC;
